+      '@phage-explorer/db-runtime': resolveFromRoot('db-runtime/src'),
+      '@phage-explorer/comparison': resolveFromRoot('comparison/src'),
+      '@phage-explorer/data-pipeline': resolveFromRoot('data-pipeline/src'),
